export KUBECONFIG=/mydata/karma/runs/short-fixrun/elasticsearch-transform-scale-upgrade-20260625_013249/bundle/kubeconfig
pw=$(kubectl -n elasticsearch get secret elastic-password -o jsonpath="{.data.password}" 2>/dev/null | base64 -d 2>/dev/null)

# Seed multiple events into app-events
kubectl -n elasticsearch exec curl-test -- curl -sk -u "elastic:$pw" \
  -XPOST "https://es-http.elasticsearch.svc:9200/_bulk?refresh=true" \
  -H "Content-Type: application/x-ndjson" \
  -d '{"index":{"_index":"app-events","_id":"1"}}
