export KUBECONFIG=/mydata/karma/runs/short-fixrun/elasticsearch-transform-scale-upgrade-20260625_013249/bundle/kubeconfig
pw=$(kubectl -n elasticsearch get secret elastic-password -o jsonpath="{.data.password}" 2>/dev/null | base64 -d 2>/dev/null)

# Create the events-by-service transform
kubectl -n elasticsearch exec curl-test -- curl -sk -u "elastic:$pw" \
  -XPUT "https://es-http.elasticsearch.svc:9200/_transform/events-by-service" \
  -H "Content-Type: application/json" \
  -d '{
    "source": {"index": "app-events"},
    "dest": {"index": "app-events-rollup"},
    "pivot": {
      "group_by": {"service": {"terms": {"field": "service"}}},
      "aggregations": {"event_count": {"value_count": {"field": "service"}}}
    },
    "sync": {"time": {"field": "@timestamp", "delay": "1s"}}
  }' 2>&1
